  ('investigation-2b298e71-moex-00012', 'investigation-2b298e71', 'investigation-2b298e71-moex-114-44c4f898', 'sub-investigation-2b298e71-04', NULL, 'single_choice', '有關修憲程序，下列敘述何者正確？', '["修憲程序是否採記名投票，應由修憲機關依議事自律原則自行決定", "基於秘密投票原則，修憲程序應採無記名投票", "修憲程序應採記名投票，始符合正當修憲程序之要求", "僅在涉及基本國策之修改時，修憲程序始應採記名投票"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:51+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "403", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "investigation", "civil_category": "調查工作組"}'::jsonb, NULL),
  ('investigation-2b298e71-moex-00013', 'investigation-2b298e71', 'investigation-2b298e71-moex-114-44c4f898', 'sub-investigation-2b298e71-04', NULL, 'single_choice', '依憲法法庭判決，對於大學教師評鑑規定之合憲性審查，應採何等審查標準？', '["因涉及大學教師職業執行自由之限制，應採寬鬆之審查標準", "因涉及大學教師職業選擇自由之主觀條件限制，攸關大學教師人格發展 ，應採較為嚴格之審查標準", "雖涉及大學教師職業選擇自由之主觀條件限制，但基於對大學自治之尊重，應採寬鬆之審查標準", "因涉及大學教師職業選擇自由之客觀條件限制，對於大學教師權益有重大影響，應採最為嚴格之審 查標準"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:51+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "403", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "調查工作組"}'::jsonb, NULL),
  ('investigation-2b298e71-moex-00014', 'investigation-2b298e71', 'investigation-2b298e71-moex-114-44c4f898', 'sub-investigation-2b298e71-04', NULL, 'single_choice', '下列何者非屬憲法集會自由保護之範圍？', '["參與政見發表會之群眾", "於夜市、鬧區街道逛街之人群", "參加社區管理委員會開會之區分所有權人", "參加元旦升旗之人群"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:51+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "403", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "調查工作組"}'::jsonb, NULL),
  ('investigation-2b298e71-moex-00015', 'investigation-2b298e71', 'investigation-2b298e71-moex-114-44c4f898', 'sub-investigation-2b298e71-04', NULL, 'single_choice', '依憲法訴訟法第47條規定得聲請憲法法庭判決者，下列敘述何者錯誤？', '["總統雖為國家最高機關，但不得聲請憲法法庭判決", "地方自治團體辦理委辦事項時，得適用憲法訴訟法第47條第2項", "行政院、立法院、司法院均得聲請憲法法庭判決", "地方自治團體辦理自治事項時，不適用憲法訴訟法第47條第2項"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:51+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "403", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "調查工作組"}'::jsonb, NULL),
  ('investigation-2b298e71-moex-00016', 'investigation-2b298e71', 'investigation-2b298e71-moex-114-44c4f898', 'sub-investigation-2b298e71-04', NULL, 'single_choice', '依司法院大法官解釋意旨，關於軍事審判官身分保障，下列敘述何者正確？', '["軍事審判官應為憲法上法官，其身分保障自以終身職為必要，有別於一般軍官", "經考試院特種考試及格志願入營服役之軍事審判官，應逕許其服現役至最大年限", "軍事審判官如有與受監護宣告相當程度之法定原因，經正當法律程序後，得予免職", "軍事審判官如有與受懲戒處分相當程度之法定原因，得由其所屬長官逕予免職"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:51+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "403", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "調查工作組"}'::jsonb, NULL),
  ('investigation-2b298e71-moex-00017', 'investigation-2b298e71', 'investigation-2b298e71-moex-114-44c4f898', 'sub-investigation-2b298e71-04', NULL, 'single_choice', '下列有關稅捐與特別公課的敘述，何者錯誤？', '["空氣污染防制費係本於污染者付費之原則，對具有造成空氣污染共同特性之污染源，徵收一定之費 用，屬於特別公課", "專對承購工業區土地、廠房及其他建築物興辦工業人課徵，用於挹注工業區開發及管理所需之工業 區開發管理基金，性質上相當於對有共同利益群體者所課徵之稅捐", "第三人稅捐協力義務之分類及差別待遇，涉及國家財政收入之整體規劃及稽徵程序之效率，適合由 代表民意之立法機關及擁有專業能力之相關行政機關決定", "公路主管機關，為公路養護、修建及安全管理所需經費而徵收之「汽車燃料使用費」，並非租稅， 但國家課予人民此一繳納金錢之義務，仍應本於正當立法目的，在必要範圍內對適當之對象以合理 之方式、額度予以課徵"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:51+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "403", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "調查工作組"}'::jsonb, NULL)
